// Complete working code for the modal dialog box
class ModalDialog {
  constructor() {
    this.modalDialog = document.getElementById('modal-dialog');
    this.modalOverlay = document.getElementById('modal-overlay');
    this.dismissButton = document.getElementById('dismiss-button');
    this.submitButton = document.getElementById('submit-button');
    this.showModalButton = document.getElementById('show-modal-button');
    this.modalDialog.querySelector('p').innerText = 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.';
  }

  show() {
    this.modalDialog.classList.remove('hidden');
    this.modalOverlay.classList.remove('hidden');
    this.dismissButton.addEventListener('click', () => this.hide());
    this.submitButton.addEventListener('click', () => alert('Modal dialog submitted')); // You can replace this with your own logic
    this.showModalButton.addEventListener('click', () => this.show());
  }

  hide() {
    this.modalDialog.classList.add('hidden');
    this.modalOverlay.classList.add('hidden');
  }

  toggleDisable() {
    this.submitButton.disabled = !this.submitButton.disabled;
  }

  checkCondition() {
    // Add your condition logic here
    this.toggleDisable();
  }
}
const modalDialog = new ModalDialog();
modalDialog.show();
